fixed_code:
use tokio::sync::mpsc;

#[tokio::main]
async fn main() {
    let (tx, mut rx) = mpsc::channel::<String>(32);

    // mpsc::Sender is Clone — just clone it directly, no Arc needed
    let tx1 = tx.clone();
    let tx2 = tx.clone();

    let t1 = tokio::spawn(async move {
        tx1.send(String::from("from task 1")).await.unwrap();
    });

    let t2 = tokio::spawn(async move {
        tx2.send(String::from("from task 2")).await.unwrap();
    });

    // Drop the original sender so the channel closes after both tasks finish
    drop(tx);

    while let Some(msg) = rx.recv().await {
        println!("{}", msg);
    }

    t1.await.unwrap();
    t2.await.unwrap();
}

