use tokio::sync::broadcast;
use tokio::time::{sleep, Duration};

#[tokio::main]
async fn main() {
    let (tx, mut rx1) = broadcast::channel::<i32>(16);

    // Spawn first subscriber immediately
    tokio::spawn(async move {
        while let Ok(val) = rx1.recv().await {
            println!("rx1: {}", val);
        }
    });

    // Send some messages before the second subscriber exists
    tx.send(1).unwrap();
    tx.send(2).unwrap();

    // Second subscriber created AFTER messages were already sent — misses them
    let mut rx2 = tx.subscribe();
    tokio::spawn(async move {
        while let Ok(val) = rx2.recv().await {
            println!("rx2: {}", val);
        }
    });

    tx.send(3).unwrap();
    sleep(Duration::from_millis(10)).await;
}

error_message:
// No compile error. rx2 will only receive message 3, silently missing 1 and 2.
// This is often surprising: broadcast channels only deliver messages
// sent AFTER the receiver was created.

fixed_code:
use tokio::sync::broadcast;
use tokio::time::{sleep, Duration};

#[tokio::main]
async fn main() {
    let (tx, mut rx1) = broadcast::channel::<i32>(16);
    // Subscribe BEFORE any sends to guarantee no messages are missed
    let mut rx2 = tx.subscribe();

    let t1 = tokio::spawn(async move {
        while let Ok(val) = rx1.recv().await {
            println!("rx1: {}", val);
        }
    });

    let t2 = tokio::spawn(async move {
        while let Ok(val) = rx2.recv().await {
            println!("rx2: {}", val);
        }
    });

    tx.send(1).unwrap();
    tx.send(2).unwrap();
    tx.send(3).unwrap();

    drop(tx);  // close the channel so receiver loops terminate
    let _ = tokio::join!(t1, t2);
}

