use tokio::sync::mpsc;
use std::sync::Arc;

#[derive(Clone, Debug)]
struct Config { timeout_ms: u64, max_retries: u32 }

#[tokio::main]
async fn main() {
    let (update_tx, mut update_rx) = mpsc::channel::<Config>(1);

    // BUG: only ONE of these tasks receives each config update
    let mut rx1 = update_rx;  // rx1 owns the receiver
    // let mut rx2 = update_rx;  // can't clone a Receiver

    tokio::spawn(async move {
        if let Some(cfg) = rx1.recv().await {
            println!("worker1 got config: {:?}", cfg);
        }
    });

    update_tx.send(Config { timeout_ms: 500, max_retries: 3 }).await.unwrap();
}

error_message:
// Compiles but only one worker ever gets the config update.
// mpsc is one-producer many-consumer: each message goes to exactly ONE receiver.
// watch channels broadcast the LATEST value to ALL receivers simultaneously.

fixed_code:
use tokio::sync::watch;

#[derive(Clone, Debug)]
struct Config { timeout_ms: u64, max_retries: u32 }

#[tokio::main]
async fn main() {
    let initial = Config { timeout_ms: 1000, max_retries: 5 };
    let (tx, rx1) = watch::channel(initial);
    let mut rx2 = rx1.clone();  // watch::Receiver is Clone
    let mut rx1 = rx1;

    let t1 = tokio::spawn(async move {
        rx1.changed().await.unwrap();
        println!("worker1 sees: {:?}", *rx1.borrow());
    });

    let t2 = tokio::spawn(async move {
        rx2.changed().await.unwrap();
        println!("worker2 sees: {:?}", *rx2.borrow());
    });

    // Update the config — all receivers see the latest value
    tx.send(Config { timeout_ms: 500, max_retries: 3 }).unwrap();

    let _ = tokio::join!(t1, t2);
}

