use tokio::sync::mpsc;

async fn producer(tx: mpsc::UnboundedSender<Vec<u8>>) {
    loop {
        // Generates data much faster than consumer processes it
        let data = vec![0u8; 1024 * 1024];  // 1 MB
        tx.send(data).unwrap();  // never blocks — memory grows forever
    }
}

async fn consumer(mut rx: mpsc::UnboundedReceiver<Vec<u8>>) {
    while let Some(data) = rx.recv().await {
        // Simulate slow processing
        tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
        println!("processed {} bytes", data.len());
    }
}

#[tokio::main]
async fn main() {
    let (tx, rx) = mpsc::unbounded_channel();
    tokio::spawn(producer(tx));
    consumer(rx).await;
}

error_message:
// No compile error. The program will exhaust memory because
// UnboundedSender::send() never yields or blocks — the producer
// can enqueue millions of items faster than the consumer can drain them.

fixed_code:
use tokio::sync::mpsc;

async fn producer(tx: mpsc::Sender<Vec<u8>>) {
    let mut count = 0u32;
    loop {
        let data = vec![0u8; 1024];  // 1 KB
        // send().await yields if the channel is full — natural backpressure
        if tx.send(data).await.is_err() {
            println!("receiver dropped, stopping producer");
            break;
        }
        count += 1;
        if count >= 20 { break; }  // finite for the example
    }
}

async fn consumer(mut rx: mpsc::Receiver<Vec<u8>>) {
    while let Some(data) = rx.recv().await {
        tokio::time::sleep(tokio::time::Duration::from_millis(5)).await;
        println!("processed {} bytes", data.len());
    }
}

#[tokio::main]
async fn main() {
    // Bounded channel: at most 8 messages in flight
    let (tx, rx) = mpsc::channel(8);
    let producer_task = tokio::spawn(producer(tx));
    consumer(rx).await;
    producer_task.await.unwrap();
}
